/**
 * Secure storage for sensitive financial data using Android KeyStore and
 * EncryptedSharedPreferences with additional encryption layer.
 */
class SecureFinancialStorage(private val context: Context) {

    companion object {
        private const val TAG = "SecureStorage"
        private const val KEYSTORE_ALIAS = "payment_module_master_key"
        private const val ENCRYPTED_PREFS_FILE = "secure_financial_prefs"
        private const val DATA_ENCRYPTION_KEY_ALIAS = "data_encryption_key"
        private const val GCM_TAG_LENGTH = 128
        private const val GCM_IV_LENGTH = 12
    }

    private val masterKey: MasterKey by lazy {
        MasterKey.Builder(context, KEYSTORE_ALIAS)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .setRequestStrongBoxBacked(true) // Use StrongBox if available
            .build()
    }

    private val encryptedPrefs by lazy {
        EncryptedSharedPreferences.create(
            context,
            ENCRYPTED_PREFS_FILE,
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }

    /**
     * Get or create a data encryption key stored in Android KeyStore.
     */
    private fun getOrCreateDataEncryptionKey(): SecretKey {
        val keyStore = KeyStore.getInstance("AndroidKeyStore")
        keyStore.load(null)

        if (keyStore.containsAlias(DATA_ENCRYPTION_KEY_ALIAS)) {
            val entry = keyStore.getEntry(DATA_ENCRYPTION_KEY_ALIAS, null) as KeyStore.SecretKeyEntry
            return entry.secretKey
        }

        val keyGenerator = KeyGenerator.getInstance(
            KeyProperties.KEY_ALGORITHM_AES,
            "AndroidKeyStore"
        )

        val builder = KeyGenParameterSpec.Builder(
            DATA_ENCRYPTION_KEY_ALIAS,
            KeyProperties.PURPOSE_ENCRYPT or KeyProperties.PURPOSE_DECRYPT
        )
            .setBlockModes(KeyProperties.BLOCK_MODE_GCM)
            .setEncryptionPaddings(KeyProperties.ENCRYPTION_PADDING_NONE)
            .setKeySize(256)
            .setUserAuthenticationRequired(false) // Set true for biometric-gated access
            .setRandomizedEncryptionRequired(true)

        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            builder.setIsStrongBoxBacked(true)
        }

        keyGenerator.init(builder.build())
        return keyGenerator.generateKey()
    }

    /**
     * Encrypt sensitive data with AES-256-GCM using KeyStore-backed key.
     */
    fun encryptSensitiveData(plaintext: String): String {
        val key = getOrCreateDataEncryptionKey()
        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        cipher.init(Cipher.ENCRYPT_MODE, key)

        val iv = cipher.iv
        val encryptedBytes = cipher.doFinal(plaintext.toByteArray(Charsets.UTF_8))

        // Combine IV + encrypted data
        val combined = ByteArray(iv.size + encryptedBytes.size)
        System.arraycopy(iv, 0, combined, 0, iv.size)
        System.arraycopy(encryptedBytes, 0, combined, iv.size, encryptedBytes.size)

        return Base64.encodeToString(combined, Base64.NO_WRAP)
    }

    /**
     * Decrypt sensitive data.
     */
    fun decryptSensitiveData(encryptedBase64: String): String {
        val key = getOrCreateDataEncryptionKey()
        val combined = Base64.decode(encryptedBase64, Base64.NO_WRAP)

        val iv = combined.copyOfRange(0, GCM_IV_LENGTH)
        val encryptedBytes = combined.copyOfRange(GCM_IV_LENGTH, combined.size)

        val cipher = Cipher.getInstance("AES/GCM/NoPadding")
        val spec = GCMParameterSpec(GCM_TAG_LENGTH, iv)
        cipher.init(Cipher.DECRYPT_MODE, key, spec)

        val decryptedBytes = cipher.doFinal(encryptedBytes)
        return String(decryptedBytes, Charsets.UTF_8)
    }

    /**
     * Store a value securely in encrypted preferences.
     */
    fun storeSecurely(key: String, value: String) {
        // Double encryption: EncryptedSharedPreferences + our own AES-GCM layer
        val doubleEncrypted = encryptSensitiveData(value)
        encryptedPrefs.edit().putString(key, doubleEncrypted).apply()
    }

    /**
     * Retrieve a securely stored value.
     */
    fun retrieveSecurely(key: String): String? {
        val doubleEncrypted = encryptedPrefs.getString(key, null) ?: return null
        return try {
            decryptSensitiveData(doubleEncrypted)
        } catch (e: Exception) {
            Log.e(TAG, "Failed to decrypt stored value", e)
            null
        }
    }

    /**
     * Securely delete a stored value.
     */
    fun deleteSecurely(key: String) {
        encryptedPrefs.edit().remove(key).apply()
    }

    /**
     * Wipe all secure storage (emergency data destruction).
     */
    fun wipeAllData() {
        encryptedPrefs.edit().clear().apply()
        try {
            val keyStore = KeyStore.getInstance("AndroidKeyStore")
            keyStore.load(null)
            keyStore.deleteEntry(DATA_ENCRYPTION_KEY_ALIAS)
        } catch (e: Exception) {
            Log.e(TAG, "Failed to wipe KeyStore entries", e)
        }
    }
}

