/**
 * Handles transaction-level security including nonce generation,
 * request signing, and replay attack prevention.
 */
class TransactionSecurity(private val context: Context) {

    companion object {
        private const val TAG = "TransactionSecurity"
        private const val NONCE_EXPIRY_MS = 5 * 60 * 1000L // 5 minutes
        private const val MAX_STORED_NONCES = 1000
    }

    private val secureRandom = SecureRandom()
    private val usedNonces = LinkedHashMap<String, Long>(MAX_STORED_NONCES, 0.75f, true)
    private val nonceLock = Any()

    /**
     * Generate a cryptographically secure transaction nonce.
     */
    fun generateTransactionNonce(): String {
        val nonceBytes = ByteArray(32)
        secureRandom.nextBytes(nonceBytes)
        val nonce = Base64.encodeToString(nonceBytes, Base64.NO_WRAP or Base64.URL_SAFE)

        synchronized(nonceLock) {
            // Clean expired nonces
            val now = System.currentTimeMillis()
            usedNonces.entries.removeAll { (_, timestamp) ->
                now - timestamp > NONCE_EXPIRY_MS
            }
            usedNonces[nonce] = now
        }

        return nonce
    }

    /**
     * Verify a nonce hasn't been used before (replay attack prevention).
     */
    fun verifyAndConsumeNonce(nonce: String): Boolean {
        synchronized(nonceLock) {
            val timestamp = usedNonces[nonce] ?: return false
            val now = System.currentTimeMillis()

            if (now - timestamp > NONCE_EXPIRY_MS) {
                usedNonces.remove(nonce)
                return false
            }

            // Consume the nonce - it can't be used again
            usedNonces.remove(nonce)
            return true
        }
    }

    /**
     * Create an HMAC signature for a transaction request.
     */
    fun signTransactionRequest(
        transactionId: String,
        amount: Long,
        currency: String,
        nonce: String,
        timestamp: Long
    ): String {
        val dataToSign = "$transactionId|$amount|$currency|$nonce|$timestamp"
        val mac = javax.crypto.Mac.getInstance("HmacSHA256")

        // In production, this key should come from a secure key exchange with the server
        val keyStore = KeyStore.getInstance("AndroidKeyStore")
        keyStore.load(null)

        val signingKeyAlias = "transaction_signing_key"
        if (!keyStore.containsAlias(signingKeyAlias)) {
            val keyGenerator = KeyGenerator.getInstance(
                KeyProperties.KEY_ALGORITHM_HMAC_SHA256,
                "AndroidKeyStore"
            )
            keyGenerator.init(
                KeyGenParameterSpec.Builder(signingKeyAlias, KeyProperties.PURPOSE_SIGN)
                    .build()
            )
            keyGenerator.generateKey()
        }

        val key = (keyStore.getEntry(signingKeyAlias, null) as KeyStore.SecretKeyEntry).secretKey
        mac.init(key)
        val signature = mac.doFinal(dataToSign.toByteArray(Charsets.UTF_8))
        return Base64.encodeToString(signature, Base64.NO_WRAP)
    }

    /**
     * Generate a unique device fingerprint for transaction binding.
     */
    fun generateDeviceFingerprint(): String {
        val components = listOf(
            Build.MANUFACTURER,
            Build.MODEL,
            Build.BOARD,
            Build.HARDWARE,
            Build.DISPLAY,
            Settings.Secure.getString(context.contentResolver, Settings.Secure.ANDROID_ID) ?: "unknown"
        )

        val digest = MessageDigest.getInstance("SHA-256")
        val combined = components.joinToString("|")
        val hash = digest.digest(combined.toByteArray(Charsets.UTF_8))
        return Base64.encodeToString(hash, Base64.NO_WRAP)
    }
}

