/**
 * Sealed class representing payment processing results.
 */
sealed class PaymentResult {
    data class Success(
        val transactionId: String,
        val amount: Long,
        val currency: String,
        val timestamp: Long
    ) : PaymentResult()

    data class Failure(
        val errorCode: PaymentErrorCode,
        val message: String,
        val transactionId: String? = null
    ) : PaymentResult()

    data class RequiresAdditionalVerification(
        val verificationType: VerificationType,
        val transactionId: String
    ) : PaymentResult()

    enum class PaymentErrorCode {
        DEVICE_INTEGRITY_FAILED,
        INSUFFICIENT_FUNDS,
        TRANSACTION_LIMIT_EXCEEDED,
        INVALID_AMOUNT,
        NETWORK_ERROR,
        SERVER_ERROR,
        ENCRYPTION_ERROR,
        NONCE_EXPIRED,
        SIGNATURE_MISMATCH,
        RATE_LIMIT_EXCEEDED,
        ACCOUNT_LOCKED,
        UNKNOWN_ERROR
    }

    enum class VerificationType {
        BIOMETRIC, TWO_FACTOR, STEP_UP_AUTH, MANUAL_REVIEW
    }
}

