    fun initialize(): InitializationResult {
        val integrityResult = performIntegrityCheck()

        return when (integrityResult.riskLevel) {
            DeviceIntegrityChecker.RiskLevel.CRITICAL -> {
                Log.e(TAG, "Critical device integrity failure: ${integrityResult.failedChecks}")
                InitializationResult.Blocked(
                    "Device does not meet security requirements for payment processing.",
                    integrityResult.failedChecks
                )
            }
            DeviceIntegrityChecker.RiskLevel.HIGH -> {
                Log.w(TAG, "High risk device detected: ${integrityResult.failedChecks}")
                InitializationResult.RestrictedMode(
                    maxTransactionAmount = MAX_TRANSACTION_AMOUNT_LOW_TRUST,
                    requiresAdditionalAuth = true,
                    warnings = integrityResult.failedChecks
                )
            }
            DeviceIntegrityChecker.RiskLevel.MEDIUM -> {
                Log.i(TAG, "Medium risk device: ${integrityResult.failedChecks}")
                InitializationResult.RestrictedMode(
                    maxTransactionAmount = MAX_TRANSACTION_AMOUNT_MEDIUM_TRUST,
                    requiresAdditionalAuth = false,
                    warnings = integrityResult.failedChecks
                )
            }
            DeviceIntegrityChecker.RiskLevel.LOW -> {
                Log.i(TAG, "Device integrity check passed. Score: ${integrityResult.integrityScore}")
                InitializationResult.Ready(
                    maxTransactionAmount = MAX_TRANSACTION_AMOUNT_HIGH_TRUST
                )
            }
        }
    }

    sealed class InitializationResult {
        data class Ready(val maxTransactionAmount: Long) : InitializationResult()
        data class RestrictedMode(
            val maxTransactionAmount: Long,
            val requiresAdditionalAuth: Boolean,
            val warnings: List<String>
        ) : InitializationResult()
        data class Blocked(
            val reason: String,
            val failedChecks: List<String>
        ) : InitializationResult()
    }

    /**
     * Perform or retrieve cached integrity check.
     */
    private fun performIntegrityCheck(): DeviceIntegrityChecker.IntegrityResult {
        val now = System.currentTimeMillis()
        val cached = cachedIntegrityResult

        if (cached != null && (now - lastIntegrityCheckTime) < integrityCheckCacheDurationMs) {
            return cached
        }

        val result = integrityChecker.performFullIntegrityCheck()
        cachedIntegrityResult = result
        lastIntegrityCheckTime = now
        return result
    }

    /**
     * Force a fresh integrity check (invalidate cache).
     */
    fun refreshIntegrityCheck(): DeviceIntegrityChecker.IntegrityResult {
        cachedIntegrityResult = null
        lastIntegrityCheckTime = 0
        return performIntegrityCheck()
    }

    /**
     * Process a wallet transaction with full security checks.
     */
    fun processWalletTransaction(
        type: WalletTransaction.TransactionType,
        amount: Long,
        currency: String
    ): PaymentResult {
        // Step 1: Validate input
        if (amount <= 0) {
            return PaymentResult.Failure(
                PaymentResult.PaymentErrorCode.INVALID_AMOUNT,
                "Transaction amount must be positive"
            )
        }

        // Step 2: Rate limiting
        if (!checkRateLimit()) {
            return PaymentResult.Failure(
                PaymentResult.PaymentErrorCode.RATE_LIMIT_EXCEEDED,
                "Too many transactions. Please wait before trying again."
            )
        }

        // Step 3: Device integrity check
        val integrityResult = performIntegrityCheck()

        if (integrityResult.riskLevel == DeviceIntegrityChecker.RiskLevel.CRITICAL) {
            return PaymentResult.Failure(
                PaymentResult.PaymentErrorCode.DEVICE_INTEGRITY_FAILED,
                "Transaction blocked due to device security concerns."
            )
        }

        // Step 4: Determine transaction limits based on device trust level
        val maxAmount = when (integrityResult.riskLevel) {
            DeviceIntegrityChecker.RiskLevel.LOW -> MAX_TRANSACTION_AMOUNT_HIGH_TRUST
            DeviceIntegrityChecker.RiskLevel.MEDIUM -> MAX_TRANSACTION_AMOUNT_MEDIUM_TRUST
            DeviceIntegrityChecker.RiskLevel.HIGH -> MAX_TRANSACTION_AMOUNT_LOW_TRUST
            DeviceIntegrityChecker.RiskLevel.CRITICAL -> 0L
        }

        if (amount > maxAmount) {
            // For high-risk devices, require step-up authentication for large amounts
            if (integrityResult.riskLevel != DeviceIntegrityChecker.RiskLevel.LOW) {
                val txId = generateTransactionId()
                return PaymentResult.RequiresAdditionalVerification(
                    verificationType = PaymentResult.VerificationType.STEP_UP_AUTH,
                    transactionId = txId
                )
            }
            return PaymentResult.Failure(
                PaymentResult.PaymentErrorCode.TRANSACTION_LIMIT_EXCEEDED,
                "Amount exceeds transaction limit of ${maxAmount / 100.0} $currency"
            )
        }

        // Step 5: For high-risk devices, always require additional verification
        if (integrityResult.riskLevel == DeviceIntegrityChecker.RiskLevel.HIGH) {
            val txId = generateTransactionId()
            return PaymentResult.RequiresAdditionalVerification(
                verificationType = PaymentResult.VerificationType.BIOMETRIC,
                transactionId = txId
            )
        }

        // Step 6: Generate transaction security tokens
        val transactionId = generateTransactionId()
        val nonce = transactionSecurity.generateTransactionNonce()
        val timestamp = System.currentTimeMillis()
        val deviceFingerprint = transactionSecurity.generateDeviceFingerprint()

        // Step 7: Sign the transaction
        val signature = try {
            transactionSecurity.signTransactionRequest(
                transactionId, amount, currency, nonce, timestamp
            )
        } catch (e: Exception) {
            Log.e(TAG, "Failed to sign transaction", e)
            return PaymentResult.Failure(
                PaymentResult.PaymentErrorCode.ENCRYPTION_ERROR,
                "Failed to secure transaction"
            )
        }

        // Step 8: Create the transaction record
        val transaction = WalletTransaction(
            transactionId = transactionId,
            type = type,
            amount = amount,
            currency = currency,
            timestamp = timestamp,
            nonce = nonce,
            signature = signature,
            deviceFingerprint = deviceFingerprint,
            integrityScore = integrityResult.integrityScore
        )

        // Step 9: Store transaction securely
        return try {
            storeTransaction(transaction)

            // Step 10: In production, send to server here
            // val serverResult = paymentApi.processTransaction(transaction)

            // For now, simulate successful processing
            PaymentResult.Success(
                transactionId = transactionId,
                amount = amount,
                currency = currency,
                timestamp = timestamp
            )
        } catch (e: Exception) {
            Log.e(TAG, "Transaction processing failed", e)
            PaymentResult.Failure(
                PaymentResult.PaymentErrorCode.UNKNOWN_ERROR,
                "Transaction processing failed: ${e.message}",
                transactionId
            )
        }
    }

    /**
     * Process an in-app purchase with integrity verification.
     */
    fun processInAppPurchase(
        productId: String,
        purchaseToken: String,
        amount: Long,
        currency: String
    ): PaymentResult {
        // Verify device integrity before processing purchase
        val integrityResult = performIntegrityCheck()

        if (!integrityResult.isTrustworthy) {
            Log.w(TAG, "In-app purchase on untrusted device. Risk: ${integrityResult.riskLevel}")

            when (integrityResult.riskLevel) {
                DeviceIntegrityChecker.RiskLevel.CRITICAL -> {
                    return PaymentResult.Failure(
                        PaymentResult.PaymentErrorCode.DEVICE_INTEGRITY_FAILED,
                        "Purchase blocked: Device integrity verification failed."
                    )
                }
                DeviceIntegrityChecker.RiskLevel.HIGH -> {
                    // Flag for server-side review but allow with additional verification
                    val txId = generateTransactionId()
                    return PaymentResult.RequiresAdditionalVerification(
                        verificationType = PaymentResult.VerificationType.TWO_FACTOR,
                        transactionId = txId
                    )
                }
                else -> {
                    // Medium risk - proceed with enhanced logging
                    Log.i(TAG, "Processing purchase on medium-risk device with enhanced monitoring")
                }
            }
        }

        // Validate purchase token format
        if (purchaseToken.isBlank() || productId.isBlank()) {
            return PaymentResult.Failure(
                PaymentResult.PaymentErrorCode.INVALID_AMOUNT,
                "Invalid purchase parameters"
            )
        }

        // Rate limiting
        if (!checkRateLimit()) {
            return PaymentResult.Failure(
                PaymentResult.PaymentErrorCode.RATE_LIMIT_EXCEEDED,
                "Too many purchase attempts"
            )
        }

        val transactionId = generateTransactionId()
        val nonce = transactionSecurity.generateTransactionNonce()
        val timestamp = System.currentTimeMillis()

        val signature = try {
            transactionSecurity.signTransactionRequest(
                transactionId, amount, currency, nonce, timestamp
            )
        } catch (e: Exception) {
            return PaymentResult.Failure(
                PaymentResult.PaymentErrorCode.ENCRYPTION_ERROR,
                "Failed to secure purchase request"
            )
        }

        // Store purchase record securely
        val purchaseData = """
            {
                "transactionId": "$transactionId",
                "productId": "$productId",
                "amount": $amount,
                "currency": "$currency",
                "timestamp": $timestamp,
                "nonce": "$nonce",
                "signature": "$signature",
                "integrityScore": ${integrityResult.integrityScore},
                "riskLevel": "${integrityResult.riskLevel}"
            }
        """.trimIndent()

        try {
            secureStorage.storeSecurely("purchase_$transactionId", purchaseData)
        } catch (e: Exception) {
            Log.e(TAG, "Failed to store purchase record", e)
        }

        // In production: verify purchase with Google Play Billing / server
        return PaymentResult.Success(
            transactionId = transactionId,
            amount = amount,
            currency = currency,
            timestamp = timestamp
        )
    }

    /**
     * Get wallet balance (securely stored).
     */
    fun getWalletBalance(): WalletBalance? {
        return try {
            val balanceData = secureStorage.retrieveSecurely(WALLET_BALANCE_KEY) ?: return null
            // Parse balance data (simplified - use proper JSON parsing in production)
            parseWalletBalance(balanceData)
        } catch (e: Exception) {
            Log.e(TAG, "Failed to retrieve wallet balance", e)
            null
        }
    }

    /**
     * Update wallet balance securely.
     */
    fun updateWalletBalance(balance: WalletBalance) {
        val balanceData = """
            {"available":${balance.available},"pending":${balance.pending},"currency":"${balance.currency}","lastUpdated":${balance.lastUpdated}}
        """.trimIndent()
        secureStorage.storeSecurely(WALLET_BALANCE_KEY, balanceData)
    }

    /**
     * Rate limiting check.
     */
    private fun checkRateLimit(): Boolean {
        synchronized(rateLimitLock) {
            val now = System.currentTimeMillis()
            transactionTimestamps.removeAll { now - it > RATE_LIMIT_WINDOW_MS }

            if (transactionTimestamps.size >= MAX_TRANSACTIONS_PER_WINDOW) {
                return false
            }

            transactionTimestamps.add(now)
            return true
        }
    }

    /**
     * Generate a unique transaction ID.
     */
    private fun generateTransactionId(): String {
        val randomBytes = ByteArray(16)
        SecureRandom().nextBytes(randomBytes)
        val timestamp = System.currentTimeMillis()
        val combined = "$timestamp-${Base64.encodeToString(randomBytes, Base64.NO_WRAP or Base64.URL_SAFE)}"
        val digest = MessageDigest.getInstance("SHA-256")
        val hash = digest.digest(combined.toByteArray())
        return "TX-" + hash.take(16).joinToString("") { "%02x".format(it) }
    }

    /**
     * Store a transaction record securely.
     */
    private fun storeTransaction(transaction: WalletTransaction) {
        val txData = """
            {
                "id":"${transaction.transactionId}",
                "type":"${transaction.type}",
                "amount":${transaction.amount},
                "currency":"${transaction.currency}",
                "timestamp":${transaction.timestamp},
                "status":"${transaction.status}",
                "integrityScore":${transaction.integrityScore}
            }
        """.trimIndent()
        secureStorage.storeSecurely(
            "$TRANSACTION_LOG_PREFIX${transaction.transactionId}",
            txData
        )
    }

    /**
     * Parse wallet balance from stored JSON string.
     */
    private fun parseWalletBalance(data: String): WalletBalance? {
        return try {
            // Simple parsing - use a proper JSON library in production
            val available = Regex(""""available":(\d+)""").find(data)?.groupValues?.get(1)?.toLong() ?: 0
            val pending = Regex(""""pending":(\d+)""").find(data)?.groupValues?.get(1)?.toLong() ?: 0
            val currency = Regex(""""currency":"([^"]+)"""").find(data)?.groupValues?.get(1) ?: "USD"
            val lastUpdated = Regex(""""lastUpdated":(\d+)""").find(data)?.groupValues?.get(1)?.toLong()
                ?: System.currentTimeMillis()

            WalletBalance(available, pending, currency, lastUpdated)
        } catch (e: Exception) {
            Log.e(TAG, "Failed to parse wallet balance", e)
            null
        }
    }

    /**
     * Emergency: Wipe all sensitive payment data from device.
     */
    fun emergencyDataWipe() {
        Log.w(TAG, "Emergency data wipe initiated")
        secureStorage.wipeAllData()
        synchronized(rateLimitLock) {
            transactionTimestamps.clear()
        }
        cachedIntegrityResult = null
    }

    /**
     * Get current security status for UI display.
     */
    fun getSecurityStatus(): SecurityStatus {
        val integrity = performIntegrityCheck()
        return SecurityStatus(
            riskLevel = integrity.riskLevel,
            integrityScore = integrity.integrityScore,
            maxTransactionAmount = when (integrity.riskLevel) {
                DeviceIntegrityChecker.RiskLevel.LOW -> MAX_TRANSACTION_AMOUNT_HIGH_TRUST
                DeviceIntegrityChecker.RiskLevel.MEDIUM -> MAX_TRANSACTION_AMOUNT_MEDIUM_TRUST
                DeviceIntegrityChecker.RiskLevel.HIGH -> MAX_TRANSACTION_AMOUNT_LOW_TRUST
                DeviceIntegrityChecker.RiskLevel.CRITICAL -> 0L
            },
            warnings = integrity.failedChecks,
            isPaymentEnabled = integrity.riskLevel != DeviceIntegrityChecker.RiskLevel.CRITICAL
        )
    }

    data class SecurityStatus(
        val riskLevel: DeviceIntegrityChecker.RiskLevel,
        val integrityScore: Int,
        val maxTransactionAmount: Long,
        val warnings: List<String>,
        val isPaymentEnabled: Boolean
    )
}

// ============================================================================
// AUDIT LOGGING MODULE
// ============================================================================

/**
 * Secure audit logger for payment-related events.
 * All logs are encrypted and tamper-evident.
 */
class SecureAuditLogger(private val context: Context) {

    companion object {
        private const val TAG = "AuditLogger"
        private const val MAX_LOG_ENTRIES = 10000
        private const val LOG_KEY_PREFIX = "audit_"
    }

    private val secureStorage = SecureFinancialStorage(context)
    private var logCounter = 0L
    private val logLock = Any()

    enum class AuditEventType {
        TRANSACTION_INITIATED,
        TRANSACTION_COMPLETED,
        TRANSACTION_FAILED,
        INTEGRITY_CHECK_PERFORMED,
        INTEGRITY_CHECK_FAILED,
        AUTHENTICATION_SUCCESS,
        AUTHENTICATION_FAILURE,
        RATE_LIMIT_HIT,
        DATA_WIPE_INITIATED,
        SUSPICIOUS_ACTIVITY_DETECTED
    }

    data class AuditEntry(
        val eventId: Long,
        val timestamp: Long,
        val eventType: AuditEventType,
        val details: String,
        val deviceFingerprint: String,
        val integrityScore: Int,
        val previousEntryHash: String
    )

    /**
     * Log an audit event with tamper-evident chaining.
     */
    fun logEvent(
        eventType: AuditEventType,
        details: String,
        integrityScore: Int = -1
    ) {
        synchronized(logLock) {
            try {
                val eventId = logCounter++
                val timestamp = System.currentTimeMillis()
                val transactionSecurity = TransactionSecurity(context)
                val deviceFingerprint = transactionSecurity.generateDeviceFingerprint()

                // Get hash of previous entry for chain integrity
                val previousHash = if (eventId > 0) {
                    val prevEntry = secureStorage.retrieveSecurely("$LOG_KEY_PREFIX${eventId - 1}")
                    if (prevEntry != null) {
                        val digest = MessageDigest.getInstance("SHA-256")
                        Base64.encodeToString(
                            digest.digest(prevEntry.toByteArray()),
                            Base64.NO_WRAP
                        )
                    } else "GENESIS"
                } else "GENESIS"

                val entry = AuditEntry(
                    eventId = eventId,
                    timestamp = timestamp,
                    eventType = eventType,
                    details = details,
                    deviceFingerprint = deviceFingerprint,
                    integrityScore = integrityScore,
                    previousEntryHash = previousHash
                )

                val entryJson = """
                    {
                        "eventId":${entry.eventId},
                        "timestamp":${entry.timestamp},
                        "eventType":"${entry.eventType}",
                        "details":"${entry.details.replace("\"", "\\\"")}",
                        "deviceFingerprint":"${entry.deviceFingerprint}",
                        "integrityScore":${entry.integrityScore},
                        "previousEntryHash":"${entry.previousEntryHash}"
                    }
                """.trimIndent()

                secureStorage.storeSecurely("$LOG_KEY_PREFIX$eventId", entryJson)

                // Rotate logs if needed
                if (logCounter > MAX_LOG_ENTRIES) {
                    secureStorage.deleteSecurely("$LOG_KEY_PREFIX${logCounter - MAX_LOG_ENTRIES}")
                }
            } catch (e: Exception) {
                Log.e(TAG, "Failed to write audit log", e)
            }
        }
    }
}

