// USAGE EXAMPLE / INTEGRATION POINT
// ============================================================================

/**
 * Example integration class showing how to use the payment module.
 */
class PaymentModuleExample(private val context: Context) {

    private val paymentProcessor = PaymentProcessor(context)
    private val auditLogger = SecureAuditLogger(context)

    fun initializePayments() {
        when (val result = paymentProcessor.initialize()) {
            is PaymentProcessor.InitializationResult.Ready -> {
                auditLogger.logEvent(
                    SecureAuditLogger.AuditEventType.INTEGRITY_CHECK_PERFORMED,
                    "Payment module initialized. Max amount: ${result.maxTransactionAmount}"
                )
                // Proceed with full payment capabilities
            }
            is PaymentProcessor.InitializationResult.RestrictedMode -> {
                auditLogger.logEvent(
                    SecureAuditLogger.AuditEventType.INTEGRITY_CHECK_FAILED,
                    "Restricted mode. Warnings: ${result.warnings}"
                )
                // Show user that some features are limited
                // Enable payments with reduced limits
            }
            is PaymentProcessor.InitializationResult.Blocked -> {
                auditLogger.logEvent(
                    SecureAuditLogger.AuditEventType.SUSPICIOUS_ACTIVITY_DETECTED,
                    "Payment blocked. Reason: ${result.reason}"
                )
                // Disable all payment features
                // Show user appropriate message
            }
        }
    }

    fun makePayment(amount: Long, currency: String) {
        auditLogger.logEvent(
            SecureAuditLogger.AuditEventType.TRANSACTION_INITIATED,
            "Payment initiated: $amount $currency"
        )

        when (val result = paymentProcessor.processWalletTransaction(
            type = WalletTransaction.TransactionType.PURCHASE,
            amount = amount,
            currency = currency
        )) {
            is PaymentResult.Success -> {
                auditLogger.logEvent(
                    SecureAuditLogger.AuditEventType.TRANSACTION_COMPLETED,
                    "Payment completed: ${result.transactionId}"
                )
                // Update UI, confirm to user
            }
            is PaymentResult.Failure -> {
                auditLogger.logEvent(
                    SecureAuditLogger.AuditEventType.TRANSACTION_FAILED,
                    "Payment failed: ${result.errorCode} - ${result.message}"
                )
                // Show error to user
            }
            is PaymentResult.RequiresAdditionalVerification -> {
                auditLogger.logEvent(
                    SecureAuditLogger.AuditEventType.AUTHENTICATION_FAILURE,
                    "Additional verification required: ${result.verificationType}"
                )
                // Prompt for biometric/2FA/step-up auth
            }
        }
    }

    fun checkSecurityStatus(): PaymentProcessor.SecurityStatus {
        return paymentProcessor.getSecurityStatus()
    }
}